import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { OrderService } from '../../core/services/order.service';
import { Order } from '../../core/models';
import { formatPrice } from '../../core/api';

@Component({
  selector: 'app-order-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './order-detail.component.html',
  styleUrl: './order-detail.component.css',
})
export class OrderDetailComponent {
  private readonly orderService = inject(OrderService);
  private readonly route = inject(ActivatedRoute);
  readonly format = formatPrice;

  readonly justPlaced = signal<boolean>(false);
  readonly order = signal<Order | null>({
    id: '1042', status: 'placed', totalCents: 6998, shipName: 'Jane Doe',
    shipAddress: '120 Foundry Rd, Ogden, UT 84401', createdAt: '2026-07-08T09:05:00Z',
    items: [
      { id: 'oi1', productId: '1', productName: 'CLASS-J Time-Delay Fuse 30A', quantity: 2, unitPriceCents: 1899 },
      { id: 'oi2', productId: '6', productName: 'Midget Fuse 10A 500V (Pack of 10)', quantity: 1, unitPriceCents: 3200 },
    ],
  });

  ngOnInit(): void {
    this.justPlaced.set(this.route.snapshot.queryParamMap.get('placed') === '1');
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) return;
    this.orderService.get(id).subscribe({
      next: (o) => this.order.set(o),
      error: () => {},
    });
  }
}
